// src/components/layouts/UserLayout.jsx
import React, { useState } from "react";

/*
  UserLayout.jsx
  -------------------------
  Simple, friendly layout for non-technical users.
  - Permanent shell (header, nav, main, footer)
  - Child pages rendered inside via internal state (no router)
  - Minimal UI, clear language, no technical jargon
  - Dummy data only (replace with APIs later)
  - Tailwind CSS utility classes used for styling
*/

/* --------------------------
   Placeholder child pages
   -------------------------- */
function DashboardPage({ user }) {
  return (
    <div className="p-6">
      <h2 className="text-xl font-semibold text-slate-900 mb-2">Welcome, {user.firstName} 👋</h2>
      <p className="text-sm text-slate-600 mb-6">Here's a quick summary of your assigned system and health status.</p>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-6">
        <div className="bg-white border rounded-lg p-4">
          <div className="text-xs text-slate-500">System</div>
          <div className="font-medium mt-2">SYS-8472</div>
          <div className="text-sm text-slate-500 mt-1">Manufacturing / Line B</div>
        </div>

        <div className="bg-white border rounded-lg p-4">
          <div className="text-xs text-slate-500">Current Health</div>
          <div className="mt-2 flex items-center gap-3">
            <div className="inline-flex items-center justify-center w-12 h-12 rounded-full bg-green-50 text-green-700 font-semibold">92</div>
            <div>
              <div className="font-medium">Healthy</div>
              <div className="text-sm text-slate-500">No action needed</div>
            </div>
          </div>
        </div>

        <div className="bg-white border rounded-lg p-4">
          <div className="text-xs text-slate-500">Last Checked</div>
          <div className="font-medium mt-2">10 minutes ago</div>
          <div className="text-sm text-slate-500 mt-1">Automatic system monitoring</div>
        </div>
      </div>

      <div className="bg-white border rounded-lg p-5">
        <h3 className="text-sm font-semibold text-slate-800 mb-2">Recent Notices</h3>
        <ul className="text-sm text-slate-600 space-y-2">
          <li>• Scheduled maintenance for Line B on Fri, 3:00 AM - 5:00 AM.</li>
          <li>• Reminder: please attach photos in support requests when possible.</li>
        </ul>
      </div>
    </div>
  );
}

function MySystemPage() {
  return (
    <div className="p-6">
      <h2 className="text-xl font-semibold text-slate-900 mb-2">My System</h2>
      <p className="text-sm text-slate-600 mb-6">
        View a friendly summary of your assigned device. If something feels wrong, request support — we’ll take it from there.
      </p>

      <div className="bg-white border rounded-lg p-5 mb-6">
        <div className="flex items-start gap-6">
          <div className="w-24 h-24 rounded-lg bg-gray-50 flex items-center justify-center text-lg font-semibold text-slate-700">
            SYS
          </div>
          <div>
            <div className="text-sm text-slate-500">System ID</div>
            <div className="font-medium mt-1">SYS-8472</div>

            <div className="text-sm text-slate-500 mt-3">Status</div>
            <div className="mt-1 inline-flex items-center gap-2">
              <span className="inline-flex items-center px-2 py-1 rounded-full bg-green-50 text-green-700 text-sm font-medium">Healthy</span>
              <span className="text-sm text-slate-500">Confidence: 92%</span>
            </div>

            <div className="text-sm text-slate-500 mt-3">Owner</div>
            <div className="mt-1 text-sm text-slate-700">Manufacturing / Line B</div>
          </div>
        </div>
      </div>

      <div className="bg-white border rounded-lg p-5">
        <h3 className="text-sm font-semibold text-slate-800 mb-2">What we monitor</h3>
        <p className="text-sm text-slate-600">
          We check your device for anything that affects reliability. This view shows only outcomes (healthy / needs attention) — no technical metrics are shown here.
        </p>
      </div>
    </div>
  );
}

function SupportRequestPage({ user }) {
  const [message, setMessage] = useState("");
  const [submitted, setSubmitted] = useState(false);

  const submit = (e) => {
    e.preventDefault();
    if (message.trim().length < 10) {
      alert("Please describe the issue in a few words so we can help.");
      return;
    }
    // UI-only: pretend to submit
    console.log("Support request submitted:", { from: user.email, message });
    setSubmitted(true);
  };

  return (
    <div className="p-6 max-w-2xl">
      <h2 className="text-xl font-semibold text-slate-900 mb-2">Support Request</h2>
      <p className="text-sm text-slate-600 mb-4">Tell us what's wrong in plain language — include photos if available.</p>

      {!submitted ? (
        <form onSubmit={submit} className="space-y-4">
          <label className="block">
            <div className="text-sm text-slate-600 mb-2">Describe the problem</div>
            <textarea
              value={message}
              onChange={(e) => setMessage(e.target.value)}
              placeholder="e.g., Machine on Line B stopped and shows a red light..."
              className="w-full p-3 border rounded-md bg-white text-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
              rows={6}
            />
          </label>

          <div className="flex items-center gap-3">
            <button type="submit" className="px-4 py-2 bg-blue-600 text-white rounded-md text-sm">
              Submit Request
            </button>
            <button type="button" onClick={() => setMessage("")} className="px-3 py-2 border rounded-md text-sm">
              Clear
            </button>
          </div>
        </form>
      ) : (
        <div className="bg-green-50 border border-green-100 p-4 rounded-md">
          <p className="text-sm text-green-800">Thanks — your request has been submitted. A technician will contact you shortly.</p>
        </div>
      )}
    </div>
  );
}

/* ---------------------------------------
   Main UserLayout component (export default)
   --------------------------------------- */
export default function UserLayout() {
  // Navigation state: local state to switch pages without routing
  const [active, setActive] = useState("dashboard");

  // Dummy user profile (replace with auth/user API)
  const user = {
    firstName: "Priya",
    lastName: "Sharma",
    email: "priya.sharma@company.com",
    avatar: "PS",
  };

  // Simple nav items
  const nav = [
    { id: "dashboard", label: "Dashboard" },
    { id: "mysystem", label: "My System" },
    { id: "support", label: "Support Request" },
  ];

  // Render selected child page
  const renderContent = () => {
    switch (active) {
      case "dashboard":
        return <DashboardPage user={user} />;
      case "mysystem":
        return <MySystemPage />;
      case "support":
        return <SupportRequestPage user={user} />;
      default:
        return <DashboardPage user={user} />;
    }
  };

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col">
      {/* Header */}
      <header className="bg-white border-b shadow-sm">
        <div className="max-w-6xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex items-center justify-between h-16">
            <div className="flex items-center gap-4">
              <div className="w-10 h-10 rounded-md bg-gradient-to-br from-blue-600 to-sky-500 flex items-center justify-center text-white font-bold">
                M
              </div>
              <div>
                <div className="text-lg font-semibold text-slate-900">MaintenanceAI</div>
                <div className="text-xs text-slate-500">Employee Portal</div>
              </div>
            </div>

            <div className="flex items-center gap-4">
              <div className="hidden sm:block text-sm text-slate-600">Signed in as {user.firstName}</div>

              <div className="flex items-center gap-3 bg-gray-100 border border-gray-200 rounded-full px-3 py-1">
                <div className="w-8 h-8 rounded-full bg-white flex items-center justify-center text-sm font-semibold text-slate-700">
                  {user.avatar}
                </div>
                <div className="text-sm text-slate-700">{user.email}</div>
              </div>
            </div>
          </div>
        </div>
      </header>

      {/* Secondary nav (minimal) */}
      <nav className="bg-white border-b">
        <div className="max-w-6xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex items-center h-12 space-x-6">
            {nav.map((n) => (
              <button
                key={n.id}
                onClick={() => setActive(n.id)}
                className={`text-sm px-3 py-2 -mb-px border-b-2 ${
                  active === n.id
                    ? "border-blue-600 text-blue-700 font-medium"
                    : "border-transparent text-slate-600 hover:text-slate-900"
                }`}
              >
                {n.label}
              </button>
            ))}
          </div>
        </div>
      </nav>

      {/* Main content area */}
      <main className="flex-1 overflow-y-auto">
        <div className="max-w-6xl mx-auto px-4 sm:px-6 lg:px-8 py-6">{renderContent()}</div>
      </main>

      {/* Footer */}
      <footer className="bg-white border-t">
        <div className="max-w-6xl mx-auto px-4 sm:px-6 lg:px-8 py-4 flex flex-col sm:flex-row items-start sm:items-center justify-between gap-3 text-sm text-slate-600">
          <div>
            <div className="font-medium text-slate-800">Need help?</div>
            <div>Contact support: <a className="text-blue-600" href="mailto:support@company.com">support@company.com</a> • +1 (800) 555-0199</div>
          </div>

          <div className="text-gray-500">
            <div>© {new Date().getFullYear()} MaintenanceAI</div>
            <div className="mt-1">Platform v1.0 • Employee view</div>
          </div>
        </div>
      </footer>
    </div>
  );
}
